mapper.select:
SELECT rr.*, cr.relic_name, cr.relic_code, su.real_name as applicant_name, approver_user.real_name as approver FROM repair_record rr LEFT JOIN cultural_relic cr ON rr.relic_id = cr.id LEFT JOIN sys_user su ON rr.applicant_id = su.id LEFT JOIN sys_user approver_user ON rr.approver = approver_user.username
AND rr.status = #{status}
AND rr.priority = #{priority}
AND cr.relic_name LIKE CONCAT('%', #{relicName}, '%')
AND rr.repair_expert LIKE CONCAT('%', #{repairExpert}, '%')
AND rr.applicant_id = #{applicantId}
ORDER BY rr.apply_date DESC, rr.id DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM repair_record rr
LEFT JOIN cultural_relic cr ON rr.relic_id = cr.id


